{"code":"import json, re
# load UNIV CALIFORNIA records
path_univ = var_call_jLvjv05XYdBAh8YEcyK3bTTF
with open(path_univ, 'r') as f:
    univ_recs = json.load(f)
# load all publicationinfo
path_all = var_call_ZvuN2QIBbAlGE7CYFmS8WbOp
with open(path_all, 'r') as f:
    all_recs = json.load(f)

# helper to extract publication number from Patents_info
pubnum_re = re.compile(r"pub\. number\s*([A-Z]{2}-[A-Z0-9\-]+)|publication number\s*([A-Z]{2}-[A-Z0-9\-]+)", re.IGNORECASE)
# Also patterns like "publication number US-11421276-B2" or "pub. number US-2022074631-A1"
pubnum_simple = re.compile(r"(US|WO|EP|JP|CN|AU|CA|TW|KR|BR|DE|FR|IN|IL|HK|MX|ZA)-[A-Z0-9\-]+", re.IGNORECASE)

univ_pubnums = set()
for rec in univ_recs:
    pi = rec.get('Patents_info','') or ''
    m = pubnum_re.search(pi)
    if m:
        num = m.group(1) or m.group(2)
        if num:
            univ_pubnums.add(num.strip())
    else:
        # fallback: find any matching pattern
        m2 = pubnum_simple.search(pi)
        if m2:
            univ_pubnums.add(m2.group(0).upper())
# Also look into 'Patents_info' for patterns like 'pub. number US-11421276-B2' already covered

# normalize to uppercase
univ_pubnums = set([u.upper() for u in univ_pubnums])

# process all records to find those that cite any of these
citing_map = {}  # assignee -> set(primary cpc codes)
citing_examples = {} # store sample rowids

# patterns to extract assignee from Patents_info
ass_patterns = [re.compile(r"^(?P<assignee>.*?)\s+holds the", re.IGNORECASE),
                re.compile(r"^(?P<assignee>.*?)\s+is owned by", re.IGNORECASE),
                re.compile(r"^(?P<assignee>.*?)\s+is assigned to", re.IGNORECASE),
                re.compile(r"^(?P<assignee>.*?)\s+assigned to", re.IGNORECASE),
                re.compile(r"^(?P<assignee>.*?)\s+owns the", re.IGNORECASE),
                re.compile(r"^(?P<assignee>.*?)\s+holds patent", re.IGNORECASE)]

for rec in all_recs:
    cit_field = rec.get('citation','') or '[]'
    try:
        cit_list = json.loads(cit_field)
    except Exception:
        # try to fix single quotes
        try:
            cit_list = json.loads(cit_field.replace("'","\""))
        except Exception:
            cit_list = []
    cites_univ = False
    for c in cit_list:
        pubnum = (c.get('publication_number') or '').upper()
        if pubnum in univ_pubnums:
            cites_univ = True
            break
    if not cites_univ:
        continue
    # extract assignee
    pi = rec.get('Patents_info','') or ''
    assignee = None
    for pat in ass_patterns:
        m = pat.search(pi)
        if m:
            assignee = m.group('assignee').strip()
            break
    if not assignee:
        # fallback: take first chunk before 'holds' or 'has' or 'owns' or ','
        m = re.split(r'\bholds\b|\bis owned by\b|\bis assigned to\b|\bassigned to\b|,', pi, flags=re.IGNORECASE)
        if m and m[0].strip():
            assignee = m[0].strip()
        else:
            assignee = pi.strip()[:200]
    # normalize
    assignee_norm = re.sub(r'\s+', ' ', assignee).upper()
    if 'UNIV CALIFORNIA' in assignee_norm:
        continue
    # get primary CPC codes
    cpcs = rec.get('cpc','') or '[]'
    try:
        cpc_list = json.loads(cpcs)
    except Exception:
        try:
            cpc_list = json.loads(cpcs.replace("'","\""))
        except Exception:
            cpc_list = []
    primary_codes = set()
    for cp in cpc_list:
        if isinstance(cp, dict) and cp.get('first'):
            code = cp.get('code')
            if code:
                primary_codes.add(code.strip().upper())
    if not primary_codes:
        # if none marked first, pick first code if exists
        for cp in cpc_list:
            if isinstance(cp, dict) and cp.get('code'):
                primary_codes.add(cp.get('code').strip().upper())
                break
    if not primary_codes:
        continue
    if assignee_norm not in citing_map:
        citing_map[assignee_norm] = set()
        citing_examples[assignee_norm] = rec.get('rowid')
    citing_map[assignee_norm].update(primary_codes)

# prepare results
citing_map_serializable = {k: sorted(list(v)) for k,v in citing_map.items()}
all_primary_symbols = sorted({s for v in citing_map_serializable.values() for s in v})
output = {'assignee_to_cpcs': citing_map_serializable, 'primary_symbols': all_primary_symbols}
print('__RESULT__:')
print(json.dumps(output))"}

